insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('6bca9e62-fa06-4c81-9ae1-fa472476a7d9', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$intro — vorming cadmiumsulfide uit cadmiumcarbonaat en zwavel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context1.png$$,
   $$In de negentiende en begin twintigste eeuw werden door de chemische industrie veel nieuwe pigmenten ontwikkeld, zoals cadmiumgeel (cadmiumsulfide, CdS). Cadmiumgeel werd onder andere gemaakt door de reactie van cadmiumcarbonaat met zwavel (S). Bij deze reactie ontstaan behalve cadmiumsulfide ook zwaveldioxide en koolstofdioxide.$$, 'inline'),
  ('6309e36b-95bf-4eab-8c03-d659d92dcf66', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$overmaat zwavel — scheiding zwavel/cadmiumsulfide door verwarmen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context2.png$$,
   $$Bij deze productie werd zwavel in overmaat toegevoegd. De overgebleven zwavel kon na afloop van de reactie gemakkelijk worden gescheiden van de gevormde cadmiumsulfide door het verkregen mengsel te verwarmen. Hierbij verdampt de zwavel maar de cadmiumsulfide niet.$$, 'inline'),
  ('2f20215f-0b55-4d05-b6a2-517e6e69c43f', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$drie aantastingen van cadmiumgeel (verbleking, witte vlekken, verkleuring PbSO4)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context3.png$$,
   $$Helaas bleek cadmiumgeel op de lange termijn niet chemisch stabiel. Op verschillende schilderijen zijn drie opeenvolgende aantastingen van cadmiumgeel waargenomen: – verbleking door de vorming van cadmiumsulfaat. – de vorming van kleine witte vlekken waarin vooral cadmiumsulfaat- monohydraat aanwezig is. – verkleuring door onder andere de vorming van lood(II)sulfaat PbSO₄. Deze verkleuring trad alleen op nadat vernis was aangebracht op een al aangetast schilderij.$$, 'inline'),
  ('b89eece8-ac28-4a33-892f-3bd6d7ffe692', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$omzetting cadmiumgeel tot cadmiumsulfaat-monohydraat (vochtige lucht)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context4.png$$,
   $$De omzetting van cadmiumgeel met zuurstof tot cadmiumsulfaat-monohydraat treedt alleen op in vochtige lucht.$$, 'inline'),
  ('558fea4a-796e-48f1-8235-80255b81b51e', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$ander zout in witte vlekken — molverhouding Cd:SO4 = 2:3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context5.png$$,
   $$Behalve cadmiumsulfaatmonohydraat ontdekte men in de witte vlekken een ander zout. In dit zout zijn cadmiumionen en sulfaationen in de molverhouding 2 : 3 aanwezig. Behalve deze ionen is er nog één andere ionsoort aanwezig. Op grond van de gevonden samenstelling van het zout vermoedden de onderzoekers dat een van de schilderijen ooit met een oplossing van ammoniak is schoongemaakt.$$, 'inline'),
  ('57aa2242-0f7d-42e6-9e8f-0c717c38b7ef', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$evenwicht CdSO4 ⇌ Cd2+ + SO4 2- en definitie Ks$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context6.png$$,
   $$Tijdens periodes met hoge luchtvochtigheid lossen de zouten die in een verflaag aanwezig zijn enigszins op. Dit wordt veroorzaakt doordat zich dan bijvoorbeeld het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄ ²⁻ kan instellen in de verflaag. De gehydrateerde ionen kunnen vervolgens door verf- en vernislagen heen bewegen. Voor het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄ ²⁻ geldt Kₛ = [Cd²⁺][SO₄ ²⁻]. Kₛ is het zogenoemde oplosbaarheidsproduct. De waardes van Ks van enkele stoffen zijn in de tabel gegeven.$$, 'inline'),
  ('39bae4ba-1c58-4311-9062-21b6bad7e064', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$tabel Ks-waardes (CdSO4, PbSO4, Pb(CH3COO)2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context7.png$$,
   $$tabel

stof formule Kₛ = … waarde van Kₛ

cadmiumsulfaat CdSO₄ [Cd²⁺][SO₄²⁻] 5,3·10⁻¹

lood(II)sulfaat PbSO₄ [Pb²⁺][SO₄²⁻] 1,7·10⁻⁸

lood(II)ethanoaat Pb(CH₃COO)₂ [Pb²⁺][CH₃COO⁻]² 2·10¹$$, 'inline'),
  ('50c03985-5f9b-41cb-a869-a3723d8ef3fc', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', $$vernislaag met lood(II)ethanoaat en gevonden PbSO4$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context8.png$$,
   $$Op een schilderij waar het cadmiumgeel al deels was omgezet tot cadmiumsulfaat is in het verleden een laag vernis aangebracht. De gebruikte vernis bevatte als enige loodverbinding lood(II)ethanoaat (Pb(CH₃COO)₂). Zowel in de verflaag als in de vernislaag is door de onderzoekers vast lood(II)sulfaat (PbSO₄) aangetroffen.$$, 'inline'),
  ('6f3096f4-c58b-47bc-b079-32b7ae6cf099', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$figuur 1 — blokschema Merox-proces (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context1.png$$,
   $$Het Merox-proces is een industrieel proces om zwavelhoudende verbindingen te verwijderen uit aardolieproducten zoals lpg. Lpg is een mengsel van koolwaterstoffen met een laag kookpunt. De zwavelhoudende verbindingen kunnen worden aangeduid met R–SH, waarbij de groep R staat voor een koolwaterstofketen. In figuur 1 is het blokschema van het Merox-proces onvolledig weergegeven.

figuur 1$$, 'inline'),
  ('0a68bd35-4c5a-4383-a834-065f2e5de13a', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$scheiding lpg/R-SH met water vs. natronloog + reactie 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context2.png$$,
   $$Het is niet mogelijk om lpg en R–SH te scheiden met behulp van water. Daarom wordt het gasvormige, nog onzuivere lpg in reactor 1 (R1) in contact gebracht met een overmaat natronloog. In R1 reageren de zwavelhoudende verbindingen volgens reactie 1.

R–SH (g) + OH⁻ (aq) → R–S⁻ (aq) + H₂O (l) (reactie 1)$$, 'inline'),
  ('c18900bf-d6e3-4985-b960-4563afe6b070', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$basische oplossing maakt scheiding mogelijk$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context3.png$$,
   $$In een basische oplossing kunnen de zwavelhoudende verbindingen wel van het lpg worden afgescheiden. Dit wordt veroorzaakt door de vorming van bindingen tussen watermoleculen en deeltjes die in R1 zijn ontstaan.$$, 'inline'),
  ('d97d9a6f-3356-4cb6-b3ff-dadc61ae2e99', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$reactiemengsel naar R2 + totaalvergelijking reacties R1/R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context4.png$$,
   $$Het reactiemengsel wordt onderin R1 afgetapt en doorgevoerd naar reactor 2 (R2). In R2 wordt een overmaat lucht door de oplossing afkomstig van R1 geleid, waarbij disulfides (R–S–S–R) worden gevormd. De totaalvergelijking van de reacties die in R1 en R2 verlopen, is hieronder weergegeven.

4 R–SH + O₂   → 2 R–S–S–R + 2 H₂O (totaalreactie)$$, 'inline'),
  ('e830e042-7772-41cc-9f19-48b3039f94e8', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$fractie [C4H10S]t/[C4H10S]0 en figuur 2 — omzettingssnelheid butaanthiol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context5.png$$,
   $$In een onderzoek is de omzettingssnelheid van R–SH tot R–S–S–R nader onderzocht. Men onderzocht de omzetting van butaanthiol (C₄H₁₀S) in

natronloog. Hierbij werd op verschillende tijdstippen de fractie [C₄H₁₀S]ₜ

[C₄H₁₀S]₀ bepaald. In figuur 2 zijn de resultaten van een meting weergegeven.

figuur 2$$, 'inline'),
  ('7efd477f-c96d-4a06-9f49-0adbd907aee5', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$beginconcentratie, molaire massa en dichtheid reactiemengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context6.png$$,
   $$Op t = 0 bevatte het mengsel 372 massa-ppm butaanthiol. De molaire massa van butaanthiol is 90,2 g mol⁻¹. De dichtheid van het reactiemengsel was 0,75 kg L⁻¹.$$, 'inline'),
  ('04364a6b-f998-4c7f-8c09-6dff48a0f2ff', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$scheidingsruimte 1 (S1) — recirculatie natronloog$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context7.png$$,
   $$In scheidingsruimte 1 (S1) wordt het vloeibare mengsel afkomstig uit R2 gescheiden. De laag met daarin de vloeibare disulfides (R–S–S–R) wordt als afval afgevoerd. De laag met natronloog bevat geen organische stoffen, zodat het natronloog kan worden hergebruikt in het proces. Om de reactie in R1 steeds onder gelijke omstandigheden te laten verlopen, moet het natronloog een bewerking ondergaan voordat het kan worden teruggevoerd.$$, 'inline'),
  ('eca32f52-c898-4a00-81fe-6eeb0c0811e8', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', $$uitwerkbijlage vraag 12 — blokschema Merox-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context8.png$$,
   $$uitwerkbijlage bij vraag 12: onvolledig blokschema van het Merox-proces, met natronloog en onzuiver lpg naar R1, R1 met uitgaande stroom lpg en een stroom natronloog/NaRS-oplossing naar R2, en R2 met een uitgaande stofstroom (*). De scheidingsruimte(n) en bijbehorende stofstromen tussen R1 en R2 ontbreken nog en moeten door de kandidaat worden ingetekend.$$, 'uitwerkbijlage'),
  ('5260616d-b266-4326-91bd-9e7f6e5148bf', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$intro EPDM-rubber + structuurformule ENB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context1.png$$,
   $$EPDM-rubber is een synthetische rubbersoort, die veel wordt gebruikt in de auto-industrie voor bijvoorbeeld afdichtingsstrips en raamrubbers. Bij de productie van EPDM-rubber wordt eerst thermoplastisch EPDM (t-EPDM) gemaakt. Hierbij ondergaat een mengsel van etheen, propeen en een zogeheten dieen een additie-polymerisatie. Een veelgebruikt dieen hierbij is ethylideen- norborneen (ENB). De structuurformule van ENB is hiernaast weergegeven. Bij de vorming van t-EPDM reageert alleen de C=C-binding die zich in de ring bevindt.$$, 'inline'),
  ('baa95da6-94e9-4e8c-b47f-d8fee0b21adb', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$katalysator type 1 en type 2 — kristallijne gebieden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context2.png$$,
   $$De polymerisatie tot t-EPDM verloopt onder invloed van een katalysator. Er zijn twee types katalysator beschikbaar: – Type 1: hiermee wordt de vorming van een willekeurig (random) copolymeer

bevorderd; – Type 2: hiermee wordt de vorming van een blok-copolymeer bevorderd. Het blijkt dat de keuze van het type katalysator een sterke invloed heeft op de vorming van kristallijne gebieden in het t-EPDM. In een kristallijn gebied vertonen de polymeerketens een grote mate van ordening. In t-EPDM zijn geen crosslinks aanwezig tussen de polymeerketens.$$, 'inline'),
  ('951e5c68-d01d-4a89-98e7-2d79f12424d8', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$vervormbaarheid t-EPDM$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context3.png$$,
   $$De vervormbaarheid van t-EPDM wordt minder naarmate het materiaal meer kristallijne gebieden bevat.$$, 'inline'),
  ('3512f882-50bd-490b-9ac0-a48846f7e4da', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$bio-ethanol uit suikerriet als grondstof voor etheen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context4.png$$,
   $$Het t-EPDM wordt vervolgens omgezet tot het eindproduct EPDM-rubber. Tot voor kort werd EPDM-rubber geproduceerd op basis van fossiele grondstoffen. In Brazilië gebruikt men nu bio-ethanol uit suikerriet in plaats van aardolie als grondstof voor het benodigde etheen. De omzetting van ethanol tot etheen is hieronder weergegeven.$$, 'inline'),
  ('0b206bd3-6e10-417d-8cc9-e35cb459528d', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$reactie 1 — omzetting ethanol tot etheen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context5.png$$,
   $$C₂H₆O (l) → C₂H₄ (g) + H₂O (l) (reactie 1)$$, 'inline'),
  ('845d9092-e35e-4480-9f8b-19a969356cb8', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$14C-atomen en Keltan-Eco (controle biogebaseerde grondstof)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context6.png$$,
   $$Het etheen afkomstig uit reactie 1 wordt vervolgens gebruikt om EPDM-rubber te produceren onder de merknaam Keltan®-Eco. Biogebaseerde producten worden gecontroleerd om misbruik van belastingvoordelen te voorkomen. Hiertoe wordt het gehalte ¹⁴C-atomen in het product bepaald. ¹⁴C-atomen worden in de atmosfeer door kosmische straling gevormd uit ¹⁴N-atomen. Uit de ¹⁴C-atomen wordt in de atmosfeer snel ¹⁴CO₂ gevormd. Het gehalte ¹⁴C in de atmosfeer is constant. Het gehalte ¹⁴C in biomassa bedraagt hierdoor gemiddeld 1,5·10⁻⁶ ppm van alle C-atomen. De ¹⁴C-atomen worden in de loop van de tijd door radioactief verval omgezet tot ¹⁴N-atomen.$$, 'inline'),
  ('e370f979-d6b2-4676-947c-2680f3e0a023', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$reactie 1 is endotherm — verbranding suikerriet-resten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context7.png$$,
   $$Reactie 1 is endotherm. De benodigde warmte wordt in het proces geleverd door verbranding van de resten van het suikerriet.$$, 'inline'),
  ('839a6129-ce7e-4ad6-ab34-caafae43125a', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$aluminiumoxide-katalysator — OH-groepen en O–-groepen op oppervlak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context8.png$$,
   $$De omzetting van ethanol tot etheen vindt plaats aan het oppervlak van een aluminiumoxide-katalysator. Op de uitwerkbijlage is een deel van het oppervlak weergegeven. Uit onderzoek is gebleken dat de OH-groepen en de O⁻-groepen aan het oppervlak een belangrijke rol spelen in de katalytische werking. Men vermoedt dat hierbij waterstofbruggen worden gevormd tussen moleculen ethanol en de aanwezige groepen op het oppervlak.$$, 'inline'),
  ('f0424190-fcc9-46f3-a384-4a79a67b6176', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$molverhoudingen etheen, propeen en ENB in Keltan-Eco$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context9.png$$,
   $$Per mol monomeereenheden van Keltan®-Eco is gemiddeld 0,55 mol etheen, 0,40 mol propeen (C₃H₆) en 0,050 mol ENB aanwezig.$$, 'inline'),
  ('74db0b3f-b4ef-41f2-82b9-7a27fab03ebd', 'd53b357b-7b2b-4764-9e5e-0eefd7db6282', $$uitwerkbijlage vraag 18 — oppervlak aluminiumoxide-katalysator$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context10.png$$,
   $$uitwerkbijlage bij vraag 18: een deel van het oppervlak van de aluminiumoxide-katalysator, met daarop OH-groepen en O⁻-groepen aan Al-atomen. De kandidaat moet intekenen hoe een molecuul ethanol met twee stippellijnen (waterstofbruggen) aan het oppervlak gebonden is.$$, 'uitwerkbijlage'),
  ('d1b92607-986f-4164-ba60-e67d649a4885', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$intro transglutaminase (TG) — koppeling glutamine en lysine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context1.png$$,
   $$In de voedselindustrie wordt soms het enzym transglutaminase (TG) gebruikt om reststukjes vlees aan elkaar te lijmen tot grotere stukken. Het enzym katalyseert de koppeling van de restgroepen van de aminozuureenheden glutamine en lysine die aanwezig zijn in peptideketens.$$, 'inline'),
  ('95045963-b839-4434-9d24-db0e87eec20a', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$figuur 1 — koppeling restgroepen glutamine en lysine (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context2.png$$,
   $$In figuur 1 is de koppeling van de restgroepen van een glutamine-eenheid en een lysine-eenheid in verschillende peptideketens schematisch en onvolledig weergegeven.

figuur 1$$, 'inline'),
  ('88fed5e4-12a5-4af2-a3ca-598e74ee1e4f', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$TG-reactie van glutamine met water i.p.v. lysine — vorming ammoniak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context3.png$$,
   $$Wanneer geen lysine-restgroepen of ongebonden aminozuren beschikbaar zijn, katalyseert TG ook de reactie tussen de restgroep van glutamine-eenheden en water. Hierbij wordt een andere aminozuur-eenheid gevormd en ontstaat ammoniak. Deze omzetting is op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('df1b59fb-9f82-4eb5-8da0-a3b6b16f9c5a', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$pH-gebied van de reactie, ~NH3+ -groep lysine en Kz$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context4.png$$,
   $$De koppeling die in de figuur is weergegeven, verloopt in een breed pH-gebied. De reactie verloopt alleen als de restgroep van de lysine-eenheid positief geladen is. Bij de gemiddelde pH van bloed zijn de aminogroepen in de restgroepen van lysine-eenheden grotendeels omgezet tot ~NH₃ ⁺-groepen. De waarde van de Kz van de NH₃ ⁺-groep is 6,3·10⁻¹¹.$$, 'inline'),
  ('fb2acc86-4afa-4e2b-b42c-c4800ceea4ca', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$NH2-groep glutamine zwakkere base dan bij lysine — grensstructuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context5.png$$,
   $$De NH₂-groep in de restgroep van glutamine is een veel zwakkere base dan de NH₂-groep in de restgroep van lysine. Dit kan worden verklaard met behulp van een grensstructuur van de restgroep van glutamine. In deze grensstructuur komen formele ladingen voor. Op de uitwerkbijlage is deze grensstructuur onvolledig weergegeven.$$, 'inline'),
  ('58661eee-4aa9-41f2-af20-939b764a43d5', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$reactiemechanisme His373/Cys314 — koppeling Lys aan Gln$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context6.png$$,
   $$In het reactiemechanisme van de koppeling van glutamine en lysine door TG spelen twee aminozuureenheden in het actieve centrum van TG een rol: His373 en Cys314. Op de uitwerkbijlage is een stap uit dit mechanisme onvolledig weergegeven. In deze stap wordt een eenheid Lys gekoppeld aan een eenheid Gln die al aan aminozuureenheid Cys314 van TG was gekoppeld.$$, 'inline'),
  ('bd630e04-c4cd-45c4-8d71-8a1a7989a5af', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$uitwerkbijlage vraag 22 — vergelijking reactie glutamine met water$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context7.png$$,
   $$uitwerkbijlage bij vraag 22: de restgroep van een glutamine-eenheid (~CH2-CH2-C(=O)-NH2) reageert met water (stippellijn) tot de restgroep van de ontstane aminozuureenheid (nog in te tekenen) plus een tweede stof (stippellijn). Ook de naam van de ontstane aminozuureenheid moet worden ingevuld.$$, 'uitwerkbijlage'),
  ('19ab51d3-c889-4a3f-9e2a-fd0f92f8101d', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$uitwerkbijlage vraag 24 — grensstructuur restgroep glutamine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context8.png$$,
   $$uitwerkbijlage bij vraag 24: onvolledige grensstructuur van de restgroep van glutamine (~CH2-CH2-C(=O)-NH2), waarin de ontbrekende niet-bindende elektronenparen en formele ladingen moeten worden ingetekend.$$, 'uitwerkbijlage'),
  ('b1d98f54-e08c-49ca-9dcf-057b6fe4814f', '7884c52d-34f1-42fc-91c0-ad5b94436539', $$uitwerkbijlage vraag 25 — reactiemechanisme koppeling Lys-Gln$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context9.png$$,
   $$uitwerkbijlage bij vraag 25: één stap uit het reactiemechanisme van de koppeling van een Lys-eenheid aan een Gln-eenheid die al aan Cys314 gekoppeld is, met His373 als hulp bij de omzetting. Links van de pijl (beginsituatie: His373, Cys314-S-C(=O)-Gln en Lys-NH2) moeten de niet-bindende elektronenparen en de vloeipijlen die de verplaatsing van elektronenparen weergeven, nog worden ingetekend; rechts van de pijl staat de eindsituatie met geprotoneerd His373 en de nieuwe binding tussen Lys en Gln.$$, 'uitwerkbijlage');

insert into practice_questions (id, exercise_id, question_number, topics, question_image_url, question_text, context_block_ids) values
  ('7a00def8-a67e-4156-a318-6268f09b6db7', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 1,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag1.png$$, $$Geef de vergelijking van deze vorming van cadmiumsulfide uit zwavel en cadmiumcarbonaat.$$, array['6bca9e62-fa06-4c81-9ae1-fa472476a7d9']::uuid[]),
  ('b2ebc040-1b5d-4a6c-bf17-1b6c58f5f772', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 2,
   '[{"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag2.png$$, $$Bereken de massa in gram zwavel die minimaal nodig is om 1,0 kg cadmiumcarbonaat volledig om te zetten tot cadmiumsulfide. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['6bca9e62-fa06-4c81-9ae1-fa472476a7d9']::uuid[]),
  ('f4d94c04-22e0-4ad7-8583-e6addc925ec3', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 3,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag3.png$$, $$Leg uit dat zwavel bij een lagere temperatuur verdampt dan cadmiumsulfide. Neem hier aan dat zwavel bestaat uit deeltjes S₈. – Gebruik hierbij begrippen op microniveau. – Benoem de bindingstypes in beide stoffen.$$, array['6309e36b-95bf-4eab-8c03-d659d92dcf66']::uuid[]),
  ('d89c9cc8-27c4-432d-bb49-5cb4c8a06bdf', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 4,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag4.png$$, $$Geef de vergelijking van de omzetting van cadmiumgeel tot cadmiumsulfaatmonohydraat.$$, array['2f20215f-0b55-4d05-b6a2-517e6e69c43f', 'b89eece8-ac28-4a33-892f-3bd6d7ffe692']::uuid[]),
  ('bb13d4fd-393b-45e1-9577-c0e8e1afd896', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 5,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag5.png$$, $$Geef een mogelijke verhoudingsformule van het gevonden zout.$$, array['558fea4a-796e-48f1-8235-80255b81b51e']::uuid[]),
  ('f1c34960-e214-4c65-bc10-8a8af12435cb', 'd5479960-cdb2-4ca1-b41a-ef224ebfc21a', 6,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag6.png$$, $$Leg uit, onder andere met behulp van evenwichtsbeschouwingen, dat lood(II)sulfaat aanwezig is in de vernislaag als gevolg van periodes met hoge luchtvochtigheid. Neem aan dat de waardes in de tabel ook gelden onder de omstandigheden in een verflaag tijdens periodes van hoge luchtvochtigheid.$$, array['57aa2242-0f7d-42e6-9e8f-0c717c38b7ef', '39bae4ba-1c58-4311-9062-21b6bad7e064', '50c03985-5f9b-41cb-a869-a3723d8ef3fc']::uuid[]),
  ('a7f35537-d367-4e7c-bc6a-bca288ddd76d', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', 7,
   '[{"domain": "Rekenen en analyse", "subdomain": "Scheidingstechnieken (filteren, destilleren, extraheren)"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag7.png$$, $$Geef de naam van de scheidingsmethode die wordt toegepast in R1.$$, array['0a68bd35-4c5a-4383-a834-065f2e5de13a', 'c18900bf-d6e3-4985-b960-4563afe6b070']::uuid[]),
  ('9779cc0a-1155-45ca-857f-ed564a1b081c', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', 8,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}, {"domain": "Rekenen en analyse", "subdomain": "Scheidingstechnieken (filteren, destilleren, extraheren)"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag8.png$$, $$Voer de volgende opdrachten uit: – Leg uit dat het niet mogelijk is om lpg en R–SH te scheiden met behulp van water. – Leg uit dat de scheiding in R1 wel mogelijk is in een basische oplossing. Benoem hierbij het bindingstype / de bindingtypes die een rol speelt/spelen bij de scheiding.$$, array['0a68bd35-4c5a-4383-a834-065f2e5de13a', 'c18900bf-d6e3-4985-b960-4563afe6b070']::uuid[]),
  ('630c4530-ab45-4e1d-aaf1-dbce279962a4', 'e4ccede8-b9b0-41ed-b60f-987699c1c072', 9,
