   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag22.png$$, $$Maak de vergelijking op de uitwerkbijlage compleet en geef de naam van de aminozuureenheid die hierbij wordt gevormd.$$, array['88fed5e4-12a5-4af2-a3ca-598e74ee1e4f', 'bd630e04-c4cd-45c4-8d71-8a1a7989a5af']::uuid[]),
  ('19bd3fc7-f898-41dc-b7ca-28c47d69995a', '7884c52d-34f1-42fc-91c0-ad5b94436539', 23,
