   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag23.png$$, $$Laat met een berekening zien dat bij pH = 7,40 het percentage aminogroepen van lysine-eenheden dat aanwezig is als ~NH₂ kleiner is dan 2,0%.$$, array['df1b59fb-9f82-4eb5-8da0-a3b6b16f9c5a']::uuid[]),
  ('941d89a3-d8f4-42cb-837c-907a52bb8677', '7884c52d-34f1-42fc-91c0-ad5b94436539', 24,
